const items = $input.all();

return items.map(item => {
  const { facture_fournisseur, mnt_facture, liste_DFFs, detail_brs_disponibles } = item.json;

  // Collecter tous les BCs uniques depuis detail_brs_disponibles
  const bcsSet = new Set();
  const dffsSet = new Set();

  (detail_brs_disponibles || []).forEach(br => {
    // BCs peuvent être séparés par virgule dans le champ BCs
    (br.BCs || '').split(',').map(s => s.trim()).filter(Boolean).forEach(bc => bcsSet.add(bc));
    if (br.DFF) dffsSet.add(br.DFF.trim());
  });

  // Aussi collecter depuis liste_DFFs au niveau racine
  (liste_DFFs || '').split(',').map(s => s.trim()).filter(Boolean).forEach(d => dffsSet.add(d));

  return {
    json: {
      facture_fournisseur,
      mnt_facture,
      liste_DFFs:  [...dffsSet].join(', '),
      liste_BCs:   [...bcsSet].join(', '),
      nb_bcs:      bcsSet.size,
      nb_dffs:     dffsSet.size
    }
  };
});

const items = $input.all();
const normalise = (s) => (s || '').trim().toUpperCase();
const arrondi   = (n) => Math.round(parseFloat(n || 0) * 100) / 100;

// ── 1. Grouper par facture → collecter tous les BRs distincts ──────────
const groupes = {};

for (const item of items) {
  const { PTHNUM_0, POHNUM_0, mnt_br, bl, facture_fournisseur, mnt_facture, DFF } = item.json;

  const keyFacture = normalise(facture_fournisseur);
  if (!keyFacture) continue;

  if (!groupes[keyFacture]) {
    groupes[keyFacture] = {
      facture_fournisseur: keyFacture,
      mnt_facture:         arrondi(mnt_facture),
      dffs:                new Set(),   // plusieurs DFF possibles pour une facture
      brs:                 {}
    };
  }

  const grp   = groupes[keyFacture];
  const keyBR = normalise(PTHNUM_0);

  // Collecter les DFF liés à cette facture
  if (DFF) grp.dffs.add(normalise(DFF));

  if (!grp.brs[keyBR]) {
    grp.brs[keyBR] = {
      BR:     PTHNUM_0,
      BCs:    new Set(),
      BL:     (bl || '').trim(),
      DFF:    DFF || '',
      mnt_br: 0
    };
  }
  grp.brs[keyBR].mnt_br = arrondi(grp.brs[keyBR].mnt_br + arrondi(mnt_br));
  grp.brs[keyBR].BCs.add(normalise(POHNUM_0));
  if (DFF) grp.brs[keyBR].DFF = DFF; // mise à jour si présent
}

// ── 2. Subset sum : trouver combinaison(s) de BRs = mnt_facture ────────
function trouverCombinations(brs, cible, tolerance = 0.01) {
  const resultats = [];

  function backtrack(index, somme, combo) {
    if (Math.abs(somme - cible) <= tolerance) {
      resultats.push([...combo]);
      return;
    }
    if (somme > cible + tolerance || index >= brs.length) return;

    for (let i = index; i < brs.length; i++) {
      combo.push(brs[i]);
      backtrack(i + 1, arrondi(somme + brs[i].mnt_br), combo);
      combo.pop();
    }
  }

  backtrack(0, 0, []);
  return resultats;
}

// ── 3. Construire résultat ─────────────────────────────────────────────
const resultats = [];

for (const grp of Object.values(groupes)) {
  const { facture_fournisseur, mnt_facture, brs, dffs } = grp;
  const brsListe     = Object.values(brs);
  const sommeTotale  = arrondi(brsListe.reduce((s, b) => s + b.mnt_br, 0));
  const combinations = trouverCombinations(brsListe, mnt_facture);
  const liste_dffs   = [...dffs].join(', ');

  if (combinations.length > 0) {
    combinations.forEach((combo, idx) => {
      resultats.push({
        statut:             'MATCH',
        facture_fournisseur,
        mnt_facture,
        liste_DFFs:         liste_dffs,
        somme_combo:        arrondi(combo.reduce((s, b) => s + b.mnt_br, 0)),
        ecart:              0,
        combinaison_nb:     idx + 1,
        nb_brs_match:       combo.length,
        nb_brs_disponibles: brsListe.length,
        liste_BRs_match:    combo.map(b => b.BR).join(', '),
        liste_BCs_match:    [...new Set(combo.flatMap(b => [...b.BCs]))].join(', '),
        brs_non_utilises:   brsListe
                              .filter(b => !combo.find(c => c.BR === b.BR))
                              .map(b => b.BR).join(', '),
        detail_brs_match:   combo.map(b => ({
          DFF:    b.DFF,
          BR:     b.BR,
          BL:     b.BL,
          BCs:    [...b.BCs].join(', '),
          mnt_br: b.mnt_br
        }))
      });
    });
  } else {
    const ecart = arrondi(sommeTotale - mnt_facture);
    resultats.push({
      statut:             sommeTotale > mnt_facture ? 'SURPLUS_BR' : 'MANQUE_BR',
      facture_fournisseur,
      mnt_facture,
      liste_DFFs:         liste_dffs,
      somme_combo:        sommeTotale,
      ecart,
      combinaison_nb:     0,
      nb_brs_match:       0,
      nb_brs_disponibles: brsListe.length,
      liste_BRs_match:    '',
      liste_BCs_match:    '',
      brs_non_utilises:   brsListe.map(b => b.BR).join(', '),
      detail_brs_match:   [],
      detail_brs_disponibles: brsListe.map(b => ({
        DFF:    b.DFF,
        BR:     b.BR,
        BL:     b.BL,
        BCs:    [...b.BCs].join(', '),
        mnt_br: b.mnt_br
      }))
    });
  }
}

// Trier : MATCH en premier, puis par mnt_facture décroissant
resultats.sort((a, b) => {
  if (a.statut === 'MATCH' && b.statut !== 'MATCH') return -1;
  if (a.statut !== 'MATCH' && b.statut === 'MATCH') return 1;
  return b.mnt_facture - a.mnt_facture;
});

return resultats.map(r => ({ json: r }));

// ============================================================
//  ANALYSEUR D'ÉCARTS ARTICLES — Nœud Code n8n  v4
//
//  Corrections v4 :
//    — codes_en_ecart ne contient que les VRAIS écarts
//      (ECART_REEL ou écart quantité) — les cas OCR_TTC_AU_LIEU_DE_HT
//      et RECEPTION_PARTIELLE_FACTUREE_TOTAL ne sont PAS des écarts
//    — Tolérance globale de 5 DH sur :
//        1. Le total facture OCR  vs  somme mnt_ht_erp_total
//        2. Le total facture OCR  vs  somme mnt_ttc_erp_total
//    — type_ecart "OK" inclut désormais les cas où
//      quantité et montant matchent (HT ou TTC)
// ============================================================

// ─── 1. CONFIGURATION ────────────────────────────────────────
const CONFIG = {
  // Tolérance par ligne (centimes)
  toleranceMontantLigne: 0.01,

  // Tolérance globale sur le total facture (en DH)
  toleranceTotalFacture: 5,

  champs: {
    code_article:     "code_article",
    code_article_erp: "code_article_erp",
    quantite_ocr:     "quantite",
    quantite_erp:     "quantity",
    montant_ht_ocr:   "montant_ht_ocr",
    montant_ht_erp:   "mnt_br_ht",
    montant_ttc_erp:  "mnt_br_ttc",
    numero_bc:        "numero_bc",
    num_facture:      "num_facture",
    dff:              "dff",
    bl:               "bl",
    id:               "id",
    // Champ optionnel : montant total de la facture OCR
    // (si présent dans vos données, ex: "mnt_facture")
    mnt_facture_ocr:  "mnt_facture",
  }
};

// ─── 2. UTILITAIRES ──────────────────────────────────────────

function round(n, dec = 2) {
  return Math.round(n * Math.pow(10, dec)) / Math.pow(10, dec);
}

function parseNum(val) {
  const n = parseFloat(val);
  return isNaN(n) ? 0 : n;
}

function get(row, fieldKey) {
  return row[CONFIG.champs[fieldKey]];
}

// ─── 3. DIAGNOSTIC MONTANT LIGNE ─────────────────────────────

function diagnostiquerMontant(mnt_ocr, mnt_ht_erp, mnt_ttc_erp) {
  const tol = CONFIG.toleranceMontantLigne;

  const delta_ocr_vs_ht  = round(mnt_ocr - mnt_ht_erp);
  const delta_ocr_vs_ttc = round(mnt_ocr - mnt_ttc_erp);

  const ecart_ocr_vs_ht  = Math.abs(delta_ocr_vs_ht)  > tol;
  const ecart_ocr_vs_ttc = Math.abs(delta_ocr_vs_ttc) > tol;

  // ocr_nature :
  //   HT_CORRECT  → OCR = HT ERP        ✓ pas d'écart
  //   TTC_EXTRAIT → OCR = TTC ERP       ✓ pas d'écart de valeur, juste de base
  //   ECART_REEL  → OCR ≠ HT ni TTC    ✗ vrai problème
  let ocr_nature;
  if      (!ecart_ocr_vs_ht)  ocr_nature = "HT_CORRECT";
  else if (!ecart_ocr_vs_ttc) ocr_nature = "TTC_EXTRAIT";
  else                         ocr_nature = "ECART_REEL";

  return {
    delta_ocr_vs_ht,
    ecart_ocr_vs_ht,
    delta_ocr_vs_ttc,
    ecart_ocr_vs_ttc,
    ocr_nature,
    ocr_extrait_ttc: ocr_nature === "TTC_EXTRAIT",
  };
}

// ─── 4. EXTRACTION DES CHAMPS D'UNE LIGNE ────────────────────

function extraireChamps(row) {
  return {
    id:            get(row, "id") || "",
    code_article:  get(row, "code_article") || get(row, "code_article_erp") || "",
    bc:            get(row, "numero_bc") || "",
    facture:       get(row, "num_facture") || "",
    dff:           get(row, "dff") || row["DFF"] || "",
    bl:            get(row, "bl") || "",
    qty_ocr:       parseNum(get(row, "quantite_ocr")),
    qty_erp:       parseNum(get(row, "quantite_erp")),
    mnt_ocr:       parseNum(get(row, "montant_ht_ocr")),
    mnt_ht_erp:    parseNum(get(row, "montant_ht_erp")),
    mnt_ttc_erp:   parseNum(get(row, "montant_ttc_erp")),
    mnt_facture:   parseNum(get(row, "mnt_facture_ocr")),
  };
}

// ─── 5. CONSOLIDATION DES DOUBLONS ───────────────────────────

function consoliderGroupes(lignes) {
  const groupes = {};
  const ordre   = [];

  lignes.forEach(row => {
    const c   = extraireChamps(row);
    const key = `${c.code_article}__${c.bc}`;

    if (!groupes[key]) {
      ordre.push(key);
      groupes[key] = {
        ids:               [],
        code_article:      c.code_article,
        bc:                c.bc,
        facture:           c.facture,
        dff:               c.dff,
        bl:                c.bl,
        qty_ocr:           c.qty_ocr,
        mnt_ocr:           c.mnt_ocr,
        mnt_facture:       c.mnt_facture,
        qty_erp_total:     0,
        mnt_ht_erp_total:  0,
        mnt_ttc_erp_total: 0,
        lignes_erp:        [],
        est_doublon:       false,
      };
    }

    const g = groupes[key];
    g.ids.push(c.id);
    g.qty_erp_total     = round(g.qty_erp_total     + c.qty_erp);
    g.mnt_ht_erp_total  = round(g.mnt_ht_erp_total  + c.mnt_ht_erp);
    g.mnt_ttc_erp_total = round(g.mnt_ttc_erp_total + c.mnt_ttc_erp);
    g.lignes_erp.push({
      id:          c.id,
      bl:          c.bl,
      qty_erp:     c.qty_erp,
      mnt_ht_erp:  c.mnt_ht_erp,
      mnt_ttc_erp: c.mnt_ttc_erp,
    });

    if (g.lignes_erp.length > 1) g.est_doublon = true;
  });

  return ordre.map(key => groupes[key]);
}

// ─── 6. ANALYSE D'UN GROUPE ──────────────────────────────────

function analyserGroupe(g) {
  // ── Quantité ─────────────────────────────────────────────
  const delta_qty = round(g.qty_ocr - g.qty_erp_total);
  const ecart_qty = delta_qty !== 0;

  // ── Montant (sur totaux consolidés) ──────────────────────
  const diag = diagnostiquerMontant(g.mnt_ocr, g.mnt_ht_erp_total, g.mnt_ttc_erp_total);

  // ── TVA implicite ─────────────────────────────────────────
  let taux_tva_implicite = null;
  if (g.mnt_ht_erp_total > 0 && g.mnt_ttc_erp_total > 0) {
    taux_tva_implicite = round((g.mnt_ttc_erp_total / g.mnt_ht_erp_total - 1) * 100);
  }

  // ── Réception partielle ───────────────────────────────────
  //  Doublon + quantité OK + montant OK (HT ou TTC)
  const reception_partielle =
    g.est_doublon &&
    !ecart_qty &&
    (diag.ocr_nature === "HT_CORRECT" || diag.ocr_nature === "TTC_EXTRAIT");

  // ── Vrai écart ? ──────────────────────────────────────────
  //  Un article EST en écart uniquement si :
  //    - écart quantité, OU
  //    - ECART_REEL sur le montant
  //  Les cas TTC_EXTRAIT et HT_CORRECT ne sont PAS des écarts
  const ecart_mnt_reel = diag.ocr_nature === "ECART_REEL";
  const vrai_ecart     = ecart_qty || ecart_mnt_reel;

  // ── Type d'écart ──────────────────────────────────────────
  let type_ecart;
  if (reception_partielle) {
    type_ecart = diag.ocr_extrait_ttc
      ? "RECEPTION_PARTIELLE_FACTUREE_TOTAL_TTC"
      : "RECEPTION_PARTIELLE_FACTUREE_TOTAL_HT";
  } else if (ecart_qty && ecart_mnt_reel) {
    type_ecart = "QTE_ET_MONTANT";
  } else if (ecart_qty) {
    type_ecart = "QUANTITE_SEULE";
  } else if (ecart_mnt_reel) {
    type_ecart = "MONTANT_SEUL_REEL";
  } else if (diag.ocr_extrait_ttc) {
    // Pas un vrai écart — OCR a capturé le TTC, valeur correcte
    type_ecart = "OK_OCR_BASE_TTC";
  } else {
    type_ecart = "OK";
  }

  // a_ecart = true UNIQUEMENT pour les vrais problèmes
  const a_ecart = vrai_ecart;

  // ── Notes ─────────────────────────────────────────────────
  const notes = [];
  if (reception_partielle)            notes.push("RECEPTION_PARTIELLE_FACTUREE_EN_TOTAL");
  if (diag.ocr_extrait_ttc)           notes.push("OCR_EXTRAIT_EN_TTC");
  if (ecart_mnt_reel)                 notes.push("ECART_MONTANT_REEL");
  if (ecart_qty && delta_qty > 0)     notes.push("QTE_OCR_SUPERIEURE_ERP");
  if (ecart_qty && delta_qty < 0)     notes.push("QTE_OCR_INFERIEURE_ERP");
  if (g.est_doublon && !reception_partielle)
    notes.push(`DOUBLON_${g.lignes_erp.length}_LIGNES_ERP`);

  return {
    ids:           g.ids,
    code_article:  g.code_article,
    numero_bc:     g.bc,
    num_facture:   g.facture,
    dff:           g.dff,
    bl:            g.bl,

    qty_ocr:           g.qty_ocr,
    qty_erp_total:     g.qty_erp_total,
    delta_qty,
    ecart_qty,

    mnt_ocr_brut:      g.mnt_ocr,
    mnt_ht_erp_total:  g.mnt_ht_erp_total,
    mnt_ttc_erp_total: g.mnt_ttc_erp_total,
    taux_tva_implicite,

    delta_ocr_vs_ht:   diag.delta_ocr_vs_ht,
    ecart_ocr_vs_ht:   diag.ecart_ocr_vs_ht,
    delta_ocr_vs_ttc:  diag.delta_ocr_vs_ttc,
    ecart_ocr_vs_ttc:  diag.ecart_ocr_vs_ttc,

    ocr_nature:        diag.ocr_nature,
    ocr_extrait_ttc:   diag.ocr_extrait_ttc,

    est_doublon:                        g.est_doublon,
    nb_lignes_erp:                      g.lignes_erp.length,
    reception_partielle_facturee_total: reception_partielle,
    detail_lignes_erp:                  g.lignes_erp,

    type_ecart,
    a_ecart,           // true = vrai problème à traiter
    notes: notes.join(" | ") || null,
  };
}

// ─── 7. CONTRÔLE TOTAL FACTURE ───────────────────────────────
//
//  Compare le montant total de la facture OCR
//  avec la somme des articles ERP (HT et TTC)
//  Tolérance : CONFIG.toleranceTotalFacture (5 DH)
//
function controlerTotalFacture(resultats, lignes) {
  const tol = CONFIG.toleranceTotalFacture;

  // Montant total facture OCR (pris sur la première ligne qui l'a)
  const mnt_facture_ocr = (() => {
    for (const row of lignes) {
      const v = parseNum(get(row, "mnt_facture_ocr"));
      if (v > 0) return v;
    }
    return null;
  })();

  // Somme des montants ERP sur tous les groupes
  const somme_ht_erp  = round(resultats.reduce((a, r) => a + r.mnt_ht_erp_total,  0));
  const somme_ttc_erp = round(resultats.reduce((a, r) => a + r.mnt_ttc_erp_total, 0));

  // Somme des montants OCR (bruts) sur tous les groupes
  const somme_ocr_brut = round(resultats.reduce((a, r) => a + r.mnt_ocr_brut, 0));

  const delta_total_ocr_vs_ht  = mnt_facture_ocr !== null ? round(mnt_facture_ocr - somme_ht_erp)  : null;
  const delta_total_ocr_vs_ttc = mnt_facture_ocr !== null ? round(mnt_facture_ocr - somme_ttc_erp) : null;
  const delta_somme_ocr_vs_ht  = round(somme_ocr_brut - somme_ht_erp);
  const delta_somme_ocr_vs_ttc = round(somme_ocr_brut - somme_ttc_erp);

  // Statut du total facture
  let statut_total_facture = "NON_DISPONIBLE";
  if (mnt_facture_ocr !== null) {
    if      (Math.abs(delta_total_ocr_vs_ht)  <= tol) statut_total_facture = "TOTAL_MATCH_HT";
    else if (Math.abs(delta_total_ocr_vs_ttc) <= tol) statut_total_facture = "TOTAL_MATCH_TTC";
    else                                               statut_total_facture = "TOTAL_ECART";
  }

  // Statut de la somme des lignes OCR vs ERP
  let statut_somme_lignes;
  if      (Math.abs(delta_somme_ocr_vs_ht)  <= tol) statut_somme_lignes = "SOMME_MATCH_HT";
  else if (Math.abs(delta_somme_ocr_vs_ttc) <= tol) statut_somme_lignes = "SOMME_MATCH_TTC";
  else                                               statut_somme_lignes = "SOMME_ECART";

  return {
    // Total facture OCR (champ mnt_facture si disponible)
    mnt_facture_ocr,
    delta_total_ocr_vs_ht,
    delta_total_ocr_vs_ttc,
    statut_total_facture,

    // Somme des montants bruts OCR ligne par ligne
    somme_ocr_brut,
    somme_ht_erp,
    somme_ttc_erp,
    delta_somme_ocr_vs_ht,
    delta_somme_ocr_vs_ttc,
    statut_somme_lignes,

    tolerance_utilisee_dh: tol,
  };
}

// ─── 8. STATISTIQUES ─────────────────────────────────────────

function calculerStats(resultats, lignes) {
  // Vrais écarts uniquement
  const vraisEcarts  = resultats.filter(r => r.a_ecart);
  const ok           = resultats.filter(r => !r.a_ecart);
  const qty_seule    = resultats.filter(r => r.type_ecart === "QUANTITE_SEULE");
  const mnt_reel     = resultats.filter(r => r.type_ecart === "MONTANT_SEUL_REEL");
  const les_deux     = resultats.filter(r => r.type_ecart === "QTE_ET_MONTANT");
  const ocr_ttc      = resultats.filter(r => r.type_ecart === "OK_OCR_BASE_TTC");
  const rec_part     = resultats.filter(r => r.reception_partielle_facturee_total);

  const somme_delta_reel = round(
    resultats.filter(r => r.ocr_nature === "ECART_REEL")
      .reduce((acc, r) => acc + Math.abs(r.delta_ocr_vs_ht), 0)
  );

  const somme_tva_capturee = round(
    resultats.filter(r => r.ocr_extrait_ttc)
      .reduce((acc, r) => acc + Math.abs(r.delta_ocr_vs_ht), 0)
  );

  const controle_total = controlerTotalFacture(resultats, lignes);

  // Nom de facture (unique, premier trouvé)
  const _res_num_facture = resultats.find(r => r.num_facture)?.num_facture ?? null;

  // Liste des DFF distincts
  const _res_dffs = [...new Set(resultats.map(r => r.dff).filter(Boolean))];

  return {
    num_facture: _res_num_facture,
    dffs:        _res_dffs,

    total_lignes_input:                 resultats.reduce((a, r) => a + r.nb_lignes_erp, 0),
    total_articles_consolides:          resultats.length,

    // Vrais écarts (à traiter)
    total_vrais_ecarts:                 vraisEcarts.length,
    total_ok:                           ok.length,
    ecart_qty_seule:                    qty_seule.length,
    ecart_mnt_reel_seul:                mnt_reel.length,
    ecart_qty_et_montant:               les_deux.length,

    // Informatif (pas des erreurs)
    articles_ocr_base_ttc:              ocr_ttc.length,
    articles_reception_partielle:       rec_part.length,

    // Montants
    somme_delta_montant_reel:           somme_delta_reel,
    somme_tva_capturee_par_ocr:         somme_tva_capturee,

    // CODES EN ÉCART = uniquement les vrais problèmes
    codes_vrais_ecarts: [...new Set(vraisEcarts.map(r => r.code_article))],

    // Codes informatifs (OCR TTC ou réception partielle, pas des erreurs)
    codes_ocr_base_ttc:     [...new Set(ocr_ttc.map(r => r.code_article))],
    codes_reception_partielle: rec_part.map(r => ({
      code_article:      r.code_article,
      numero_bc:         r.numero_bc,
      nb_lignes_erp:     r.nb_lignes_erp,
      qty_ocr:           r.qty_ocr,
      qty_erp_total:     r.qty_erp_total,
      mnt_ocr_brut:      r.mnt_ocr_brut,
      mnt_ht_erp_total:  r.mnt_ht_erp_total,
      mnt_ttc_erp_total: r.mnt_ttc_erp_total,
      ocr_nature:        r.ocr_nature,
      detail_lignes_erp: r.detail_lignes_erp,
    })),

    // Contrôle total facture (avec tolérance 5 DH)
    controle_total_facture: controle_total,
  };
}

// ─── 9. ENTRÉE N8N ───────────────────────────────────────────

let lignes = [];

for (const item of $input.all()) {
  const d = item.json;
  if (Array.isArray(d))                       lignes = lignes.concat(d);
  else if (Array.isArray(d.data))             lignes = lignes.concat(d.data);
  else if (Array.isArray(d.items))            lignes = lignes.concat(d.items);
  else if (Array.isArray(d.rows))             lignes = lignes.concat(d.rows);
  else if (d && d.code_article !== undefined) lignes.push(d);
}

